mapper.select:
SELECT cel_tags.tag_name FROM
ig_celebrity_tags
youtube_celebrity_tags
tiktok_celebrity_tags
cel_tags JOIN (
SELECT DISTINCT tag_name FROM (
SELECT tar.tag_name FROM kol_category_attribute_relation car INNER JOIN kol_attribute ka ON car.attribute_category_id = ka.id INNER JOIN kol_attribute ka2 ON ka2.attribute_name = SUBSTRING_INDEX(ka.attribute_name_path, '|', 1) INNER JOIN kol_tag_attribute_relation tar ON tar.attribute_id = ka2.id left join kol_tags atr on tar.tag_id = atr.id AND atr.platform_type = #{platformType} WHERE atr.is_active =1 and atr.is_delete =0 and car.category_id IN
#{categoryId}
) all_tags WHERE tag_name IS NOT NULL AND tag_name != ''
) b ON cel_tags.tag_name = b.tag_name WHERE cel_tags.country = #{countryCode}
group by tag_name

SELECT ktp.tag_name
FROM kol_tag_product ktp
WHERE ktp.product_id = #{searchModel.productId}
  and ktp.platform_type = #{searchModel.platformType}

SELECT tar.tag_name
FROM kol_tag_attribute_relation tar
STRAIGHT_JOIN kol_tags atr on tar.tag_id = atr.id
WHERE
tar.attribute_id IN

    #{attributeId}

and atr.platform_type = #{searchModel.platformType}

    AND tar.product_id = #{searchModel.productId}

AND atr.is_active =1
and atr.is_delete =0
